let state = { likes: 10 };

async function toggleLikeOptimistic() {
  // 1. OPTIMISTIC UPDATE: Update UI instantly, assuming success
  state.likes++;
  render(state); // UI feels lightning fast

  try {
    // 2. BACKGROUND WORK: Send the request to the server
    const res = await fetch('/api/like', { method: 'POST' });
    if (!res.ok) throw new Error('Server failed');
    // Success! Do nothing, UI is already correct.

  } catch (error) {
    // 3. ROLLBACK: Only if it fails do we revert the UI
    console.warn('Like failed, rolling back UI.');
    state.likes--;
    render(state);
    showToast('Failed to save like. Please check connection.');
  }
}

